    const buffer = new Uint8Array(arrayBuffer);
    const result = await new Promise((resolve, reject) => {
      cloudinary.uploader.upload_stream({ folder: "hotwheels-store" }, (error, result) => {
          if (error) reject(error); else resolve(result);
