    setEditingId(addr._id);
    setFormData({
      street: addr.street,
      city: addr.city,
      state: addr.state,
      zip: addr.zip,
      country: addr.country
    });
    setIsAdding(true);
  };

  const handleSave = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    let res;

    if (editingId) {
      res = await updateAddress(userId, editingId, formData);
    } else {
      res = await addAddress(userId, formData);
    }

    if (res?.success) {
      addToast(editingId ? "Address updated successfully" : "Address added successfully", "success");
      resetForm();
    } else {
